mapper.update:
UPDATE student
SET
    violation_count = violation_count + 1,
    violation_score = violation_score + #{score}
WHERE id = #{id}

mapper.select:
SELECT s.*, c.name clazz_name FROM student s LEFT JOIN clazz c ON s.clazz_id = c.id
AND s.name LIKE CONCAT('%',#{name},'%')
AND s.degree = #{degree}
AND s.clazz_id = #{clazzId}
ORDER BY s.update_time DESC

SELECT
    id, name, no, gender, phone, degree, id_card, is_college, address, graduation_date, violation_count, violation_score, clazz_id, create_time, update_time
FROM student WHERE id = #{id}
